"use client";

import React from "react";
import { Modal } from "@/components/ui/modal";
import Button from "@/components/ui/button/Button";
import Input from "@/components/form/input/InputField";
import Label from "@/components/form/Label";
import {
  calculateDueDate,
  type CreditAccount,
  type CreditAccountForm,
  type Customer,
} from "./CreditAccountsClient";

type Props = {
  isOpen: boolean;
  onClose: () => void;
  editingAccount: CreditAccount | null;
  customers: Customer[];
  form: CreditAccountForm;
  setForm: React.Dispatch<React.SetStateAction<CreditAccountForm>>;
  onSubmit: (e: React.FormEvent) => void;
};

const selectClass =
  "h-11 w-full rounded-lg border border-gray-300 bg-transparent px-4 py-2.5 text-sm text-gray-800 shadow-theme-xs focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90";

export default function CreditAccountModal({
  isOpen,
  onClose,
  editingAccount,
  customers,
  form,
  setForm,
  onSubmit,
}: Props) {
  const displayedDueDate = calculateDueDate(
    form.start_date,
    form.installment_count
  );

  return (
    <Modal isOpen={isOpen} onClose={onClose} className="max-w-[800px] m-4">
      <div className="no-scrollbar relative w-full max-w-[800px] overflow-y-auto rounded-3xl bg-white p-4 dark:bg-gray-900 lg:p-11">
        <div className="px-2 pr-14">
          <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
            {editingAccount ? "Edit Credit Account" : "Add Credit Account"}
          </h4>

          <p className="mb-6 text-sm text-gray-500 dark:text-gray-400 lg:mb-7">
            Enter credit account details below.
          </p>
        </div>

        <form
          key={editingAccount?.id || "new-credit-account"}
          onSubmit={onSubmit}
          className="flex flex-col"
        >
          <div className="custom-scrollbar max-h-[520px] overflow-y-auto px-2 pb-3">
            <h5 className="mb-5 text-lg font-medium text-gray-800 dark:text-white/90 lg:mb-6">
              Account Information
            </h5>

            <div className="grid grid-cols-1 gap-x-6 gap-y-5 lg:grid-cols-2">
              <div className="lg:col-span-2">
                <Label>Customer</Label>

                <select
                  className={`${selectClass} ${
                    editingAccount
                      ? "cursor-not-allowed bg-gray-100 opacity-75 dark:bg-gray-800"
                      : ""
                  }`}
                  value={form.customer_id}
                  onChange={(e) =>
                    setForm({ ...form, customer_id: e.target.value })
                  }
                  required
                  disabled={!!editingAccount}
                >
                  <option value="">Select customer</option>

                  {customers.map((customer) => (
                    <option key={customer.id} value={customer.id}>
                      {customer.full_name_ar}
                      {customer.full_name_en
                        ? ` / ${customer.full_name_en}`
                        : ""}{" "}
                      - {customer.mobile_number}
                    </option>
                  ))}
                </select>

                {editingAccount && (
                  <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
                    Customer cannot be changed after the credit account is
                    created.
                  </p>
                )}
              </div>

              <div>
                <Label>Account Type</Label>
                <select
                  className={selectClass}
                  value={form.account_type}
                  onChange={(e) =>
                    setForm({
                      ...form,
                      account_type: e.target.value,
                      installment_count: "",
                      installment_value: "",
                      billing_cycle: "",
                      credit_limit: "",
                    })
                  }
                >
                  <option value="fixed_installment">
                    Fixed instalment account
                  </option>
                  <option value="open_ended">
                    Open-ended / utility account
                  </option>
                </select>
              </div>

              <div>
                <Label>Product Type</Label>
                <Input
                  type="text"
                  defaultValue={form.product_type}
                  placeholder="Phone, electricity, water bill..."
                  onChange={(e) =>
                    setForm({ ...form, product_type: e.target.value })
                  }
                />
              </div>

              <div>
                <Label>Principal Amount</Label>
                <Input
                  type="number"
                  step="0.01"
                  defaultValue={form.principal_amount}
                  onChange={(e) =>
                    setForm({
                      ...form,
                      principal_amount: e.target.value,
                      total_payable: e.target.value,
                    })
                  }
                  required
                />
              </div>

              <div>
                <Label>Total Payable</Label>
                <Input
                  type="number"
                  step="0.01"
                  defaultValue={form.total_payable}
                  onChange={(e) =>
                    setForm({ ...form, total_payable: e.target.value })
                  }
                  required
                />
              </div>

              <div>
                <Label>Start Date</Label>
                <Input
                  type="date"
                  defaultValue={form.start_date}
                  onChange={(e) =>
                    setForm({ ...form, start_date: e.target.value })
                  }
                  required
                />
              </div>

              {form.account_type === "fixed_installment" && (
                <>
                  <div>
                    <Label>Installment Count</Label>
                    <Input
                      type="number"
                      defaultValue={form.installment_count}
                      onChange={(e) =>
                        setForm({
                          ...form,
                          installment_count: e.target.value,
                        })
                      }
                      required
                    />
                  </div>

                  <div>
                    <Label>Installment Value</Label>
                    <Input
                      type="number"
                      step="0.01"
                      defaultValue={form.installment_value}
                      onChange={(e) =>
                        setForm({
                          ...form,
                          installment_value: e.target.value,
                        })
                      }
                      required
                    />
                  </div>

                  <div>
                    <Label>Calculated Due Date</Label>
                    <Input type="date" value={displayedDueDate} readOnly />
                  </div>
                </>
              )}

              {form.account_type === "open_ended" && (
                <>
                  <div>
                    <Label>Credit Limit / Expected Bill</Label>
                    <Input
                      type="number"
                      step="0.01"
                      defaultValue={form.credit_limit}
                      onChange={(e) =>
                        setForm({ ...form, credit_limit: e.target.value })
                      }
                    />
                  </div>

                  <div>
                    <Label>Billing Cycle</Label>
                    <select
                      className={selectClass}
                      value={form.billing_cycle}
                      onChange={(e) =>
                        setForm({ ...form, billing_cycle: e.target.value })
                      }
                    >
                      <option value="">Select billing cycle</option>
                      <option value="monthly">Monthly</option>
                      <option value="weekly">Weekly</option>
                      <option value="irregular">Irregular</option>
                    </select>
                  </div>
                </>
              )}
            </div>
          </div>

          <div className="flex items-center gap-3 px-2 mt-6 lg:justify-end">
            <Button size="sm" variant="outline" type="button" onClick={onClose}>
              Close
            </Button>

            <Button size="sm" type="submit">
              {editingAccount ? "Save Changes" : "Add Credit Account"}
            </Button>
          </div>
        </form>
      </div>
    </Modal>
  );
}