"use client";

import React, { useEffect, useState } from "react";
import ComponentCard from "@/components/common/ComponentCard";
import PageBreadcrumb from "@/components/common/PageBreadCrumb";
import { apiFetch } from "@/lib/api";
import CreditAccountsTable from "./CreditAccountsTable";
import CreditAccountModal from "./CreditAccountModal";

export type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
};

export type CreditAccount = {
  id: string;
  customer_id: string;
  account_type?: string;
  billing_cycle?: string;
  credit_limit?: number;
  product_type?: string;
  principal_amount: number;
  total_payable: number;
  installment_count?: number;
  installment_value?: number;
  balance_remaining: number;
  start_date?: string;
  due_date?: string;
  status?: string;
};

export type CreditAccountForm = {
  customer_id: string;
  account_type: string;
  product_type: string;
  principal_amount: string;
  total_payable: string;
  installment_count: string;
  installment_value: string;
  start_date: string;
  billing_cycle: string;
  credit_limit: string;
};

const emptyForm: CreditAccountForm = {
  customer_id: "",
  account_type: "fixed_installment",
  product_type: "",
  principal_amount: "",
  total_payable: "",
  installment_count: "",
  installment_value: "",
  start_date: "",
  billing_cycle: "",
  credit_limit: "",
};

export function calculateDueDate(startDate: string, installmentCount: string) {
  if (!startDate || !installmentCount) return "";

  const count = Number(installmentCount);
  if (Number.isNaN(count) || count <= 0) return "";

  const [year, month, day] = startDate.split("-").map(Number);
  const date = new Date(year, month - 1, day);

  date.setMonth(date.getMonth() + count);

  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const dd = String(date.getDate()).padStart(2, "0");

  return `${yyyy}-${mm}-${dd}`;
}

export default function CreditAccountsClient() {
  const [accounts, setAccounts] = useState<CreditAccount[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [isOpen, setIsOpen] = useState(false);
  const [editingAccount, setEditingAccount] = useState<CreditAccount | null>(
    null
  );
  const [form, setForm] = useState<CreditAccountForm>(emptyForm);

  useEffect(() => {
    loadData();
  }, []);

  async function loadData() {
    try {
      setLoading(true);
      setError("");

      const [accountsData, customersData] = await Promise.all([
        apiFetch("/merchant/credit-accounts"),
        apiFetch("/merchant/customers"),
      ]);

      setAccounts(accountsData);
      setCustomers(customersData);
    } catch (err: any) {
      setError(err.message || "Failed to load credit accounts");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingAccount(null);
    setForm(emptyForm);
    setIsOpen(true);
  }

  function openEditModal(account: CreditAccount) {
    setEditingAccount(account);

    setForm({
      customer_id: account.customer_id || "",
      account_type: account.account_type || "fixed_installment",
      product_type: account.product_type || "",
      principal_amount: String(account.principal_amount || ""),
      total_payable: String(account.total_payable || ""),
      installment_count: String(account.installment_count || ""),
      installment_value: String(account.installment_value || ""),
      start_date: account.start_date?.slice(0, 10) || "",
      billing_cycle: account.billing_cycle || "",
      credit_limit: String(account.credit_limit || ""),
    });

    setIsOpen(true);
  }

  function closeModal() {
    setIsOpen(false);
    setEditingAccount(null);
    setForm(emptyForm);
  }

  async function saveCreditAccount(e: React.FormEvent) {
    e.preventDefault();

    const isFixed = form.account_type === "fixed_installment";
    const displayedDueDate = calculateDueDate(
      form.start_date,
      form.installment_count
    );

    const payload = {
      customer_id: form.customer_id,
      account_type: form.account_type,
      product_type: form.product_type,

      principal_amount: Number(form.principal_amount || 0),
      total_payable: Number(form.total_payable || form.principal_amount || 0),

      installment_count: isFixed ? Number(form.installment_count || 0) : null,
      installment_value: isFixed ? Number(form.installment_value || 0) : null,

      start_date: form.start_date ? `${form.start_date}T00:00:00Z` : null,

      due_date:
        isFixed && displayedDueDate ? `${displayedDueDate}T00:00:00Z` : null,

      billing_cycle: isFixed ? null : form.billing_cycle,
      credit_limit: isFixed ? null : Number(form.credit_limit || 0),
    };

    try {
      setError("");

      if (editingAccount) {
        await apiFetch(`/merchant/credit-accounts/${editingAccount.id}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });
      } else {
        await apiFetch("/merchant/credit-accounts", {
          method: "POST",
          body: JSON.stringify(payload),
        });
      }

      closeModal();
      await loadData();
    } catch (err: any) {
      setError(err.message || "Failed to save credit account");
    }
  }

  async function markAsSettled(id: string) {
    if (!confirm("Mark this credit account as settled?")) return;

    try {
      setError("");

      await apiFetch(`/merchant/credit-accounts/${id}/settle`, {
        method: "PATCH",
      });

      await loadData();
    } catch (err: any) {
      setError(err.message || "Failed to settle credit account");
    }
  }

  function getCustomerName(customerId: string) {
    const customer = customers.find((c) => c.id === customerId);

    if (!customer) return customerId;

    return `${customer.full_name_ar}${
      customer.full_name_en ? ` / ${customer.full_name_en}` : ""
    }`;
  }

  const totalPages = Math.ceil(accounts.length / pageSize);

  const paginatedAccounts = accounts.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <div>
      <PageBreadcrumb pageTitle="الحسابات الائتمانية" />

      <div className="space-y-6">
        <ComponentCard>
          <div className="mb-5 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h4 className="text-lg font-semibold text-gray-800 dark:text-white/90">
                الحسابات الائتمانية
              </h4>
              <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
               إضافة ، تعديل أو ترقين الحسابات الائتمانية/القروض
              </p>
            </div>

            <button
              onClick={openAddModal}
             className="inline-flex items-center justify-center rounded-lg bg-[#00A65A] px-4 py-2.5 text-sm font-medium text-white hover:bg-[#008C4A] transition-colors duration-200"
            >
              إضافة حساب جديد
            </button>
          </div>

          {error && (
            <div className="mb-5 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
              {error}
            </div>
          )}

          <CreditAccountsTable
            accounts={paginatedAccounts}
            loading={loading}
            getCustomerName={getCustomerName}
            onEdit={openEditModal}
            onSettle={markAsSettled}
          />

          <div className="mt-4 flex items-center justify-between">
            <button
              onClick={() => setPage((p) => Math.max(p - 1, 1))}
              disabled={page === 1}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              السابق
            </button>

            <span className="text-sm text-gray-500 dark:text-gray-400">
              الصفحة {page} من {totalPages || 1}
            </span>

            <button
              onClick={() => setPage((p) => Math.min(p + 1, totalPages))}
              disabled={page === totalPages || totalPages === 0}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              التالي
            </button>
          </div>
        </ComponentCard>
      </div>

      <CreditAccountModal
        isOpen={isOpen}
        onClose={closeModal}
        editingAccount={editingAccount}
        customers={customers}
        form={form}
        setForm={setForm}
        onSubmit={saveCreditAccount}
      />
    </div>
  );
}