"use client";

import React from "react";
import Badge from "@/components/ui/badge/Badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import type { CreditAccount } from "./CreditAccountsClient";

type Props = {
  accounts: CreditAccount[];
  loading: boolean;
  getCustomerName: (customerId: string) => string;
  onEdit: (account: CreditAccount) => void;
  onSettle: (id: string) => void;
};

export default function CreditAccountsTable({
  accounts,
  loading,
  getCustomerName,
  onEdit,
  onSettle,
}: Props) {
  return (
    <div className="overflow-hidden rounded-xl border border-gray-200 bg-white dark:border-white/[0.05] dark:bg-white/[0.03]">
      <div className="max-w-full overflow-x-auto">
        <div className="min-w-[1400px]">
          <Table>
            <TableHeader className="border-b border-gray-100 dark:border-white/[0.05]">
              <TableRow>
                {[
                  "الاسم",
                  "نوع الحساب",
                  "المنتج",
                  "المبلغ الاساسي",
                  "المبلغ النهائي",
                  "الدفعات",
                  "العدد",
                  "الرصيد",
                  "تاريخ الاستحقاق",
                  "الحالة",
                  "",
                ].map((header) => (
                  <TableCell
                    key={header}
                    isHeader
                    className="px-5 py-3 font-medium text-gray-500 text-start text-theme-xs dark:text-gray-400"
                  >
                    {header}
                  </TableCell>
                ))}
              </TableRow>
            </TableHeader>

            <TableBody className="divide-y divide-gray-100 dark:divide-white/[0.05]">
              {loading ? (
                <TableRow>
                  <TableCell className="px-5 py-6 text-center text-gray-500 text-theme-sm dark:text-gray-400">
                    Loading credit accounts...
                  </TableCell>
                </TableRow>
              ) : accounts.length === 0 ? (
                <TableRow>
                  <TableCell className="px-5 py-6 text-center text-gray-500 text-theme-sm dark:text-gray-400">
                    No credit accounts found.
                  </TableCell>
                </TableRow>
              ) : (
                accounts.map((account) => {
                  const status = account.status || "unknown";
                  const normalStatus = status.toLowerCase();

                  return (
                    <TableRow key={account.id}>
                      <TableCell className="px-5 py-4 sm:px-6 text-start">
                        <span className="block font-medium text-gray-800 text-theme-sm dark:text-white/90">
                          {getCustomerName(account.customer_id)}
                        </span>
                        
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.account_type || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.product_type || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.principal_amount}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.total_payable}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.account_type === "fixed_installment"
                          ? `${account.installment_count || 0} × ${
                              account.installment_value || 0
                            }`
                          : "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.billing_cycle || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.balance_remaining}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {account.due_date ? account.due_date.slice(0, 10) : "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        <Badge
                          size="sm"
                          color={
                            normalStatus === "active"
                              ? "success"
                              : normalStatus === "settled"
                              ? "success"
                              : normalStatus === "overdue"
                              ? "error"
                              : "warning"
                          }
                        >
                          {status}
                        </Badge>
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-theme-sm dark:text-gray-400">
                        <div className="flex items-center gap-2">
                          <button
                            type="button"
                            onClick={() => onEdit(account)}
                            className="rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
                          >
                            تعديل
                          </button>

                          {normalStatus !== "settled" &&
                            account.account_type === "fixed_installment" && (
                              <button
                                type="button"
                                onClick={() => onSettle(account.id)}
                                className="rounded-lg bg-success-500 px-3 py-1.5 text-sm font-medium text-white hover:bg-success-600"
                              >
                                ترقين
                              </button>
                            )}
                        </div>
                      </TableCell>
                    </TableRow>
                  );
                })
              )}
            </TableBody>
          </Table>
        </div>
      </div>
    </div>
  );
}